        if not s:
            return 0
        if len(s) == 1:
            return 1

        ret = 0
        n = len(s)

        def countPalindromes(s, l, r):
            c = 0
            while l >= 0 and r < n and s[l] == s[r]:
                c += 1
                l -= 1
                r += 1
            return c

