class Solution:
    def rob(self, nums: List[int]) -> int:
        def get_max(nums):
            prev_rob = max_rob = 0

            for cur in nums:
                temp = max(max_rob, prev_rob + cur)
                prev_rob = max_rob
                max_rob = temp

            return max_rob
        # Either we take first and not last
