class Solution:
    def findRedundantConnection(self, edges: List[List[int]]) -> List[int]:
        n = len(edges)

        parent = [i for i in range(n+1)]
        rank = [1] * (n + 1)

        def find(n: int) -> int:
            if n == parent[n]:
                return parent[n]

            parent[n] = find(parent[n])
            return parent[n]

        def union(n1: int, n2: int) -> bool:
            p1 = find(n1)
            p2 = find(n2)

            if p1 == p2:
                return False

            if rank[p1] > rank[p2]:
                parent[p2] = p1
                rank[p1] += rank[p2]
            else:
                parent[p1] = p2
                rank[p2] += rank[p1]

            return True

        for n1, n2 in edges:
            if not union(n1, n2):
                return [n1, n2]

