                r, c = q.popleft()
                for dr, dc in directions:
                    row, col = dr + r, dc + c
                    # if in bounds and fresh, make rotten
                    if (row < 0 or row == len(grid) or \
                        col < 0 or col == len(grid[0]) or\
                        grid[row][col] != 1):
