            if r == ROWS or c == COLS or \
                r < 0 or c < 0 or \
                grid[r][c] == 0:
                return 1
            if (r, c) in visited:
                return 0

            visited.add((r,c))

            ret = dfs(r, c + 1)
            ret += dfs(r, c - 1)
            ret += dfs(r + 1, c)
            ret += dfs(r - 1, c)

            return ret

        for r in range(ROWS):
            for c in range(COLS):
                if grid[r][c] == 1: return dfs(r, c)

