class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:

        # Make TRIE with input words
        # Search while dfs-ing + backtracking?

        '''
        For each position in graph, start greedy search and
        check if current character is in Trie. If no, move to next word.
        If yes, move recursively to adjacent positions and check if they are
        children of parent node.
        '''

        root = TrieNode()

        for w in words:
            root.addWord(w)

        rows, cols = len(board), len(board[0])

        res, visit = set(), set()

        def dfs(r, c, node, word):
            if (r < 0 or c < 0 or \
                r == rows or c == cols or \
                (r,c) in visit or board[r][c] not in node.children):
                return

            visit.add((r,c))
            node = node.children[board[r][c]]
            word += board[r][c]
            if node.isWord:
                res.add(word)

            dfs(r-1, c, node, word)
            dfs(r+1, c, node, word)
            dfs(r, c-1, node, word)
            dfs(r, c+1, node, word)

            visit.remove((r,c))

        for r in range(rows):
            for c in range(cols):
                dfs(r, c, root, "")

        return list(res)

