            trieRoot.insertWord(word)
        trieRoot = trieRoot.root

        ret, visited = set(), set()

        def dfs(r: int, c: int, node: Trie, word: str) -> None:
            if r == ROWS or r < 0 or \
                c == COLS or c < 0 or \
                (r, c) in visited or \
                board[r][c] not in node.children:
                return

            # Add current character 
            visited.add((r,c))
            # Since board[r][c] is in node.children (as found in base case)
            node = node.children[board[r][c]]   
            word += board[r][c]

            # If the current position in Trie forms a word, add to result
            if node.isEnd:
                ret.add(word[::])

            dfs(r + 1, c, node, word)
            dfs(r - 1, c, node, word)
            dfs(r, c + 1, node, word)
            dfs(r, c - 1, node, word)

            # Backtrack
            visited.remove((r,c))

        for r in range(ROWS):
            for c in range(COLS):
                if board[r][c] in trieRoot.children:
                    dfs(r, c, trieRoot, "")

