class Solution:
    def pointDistance(self, x1, x2) -> float:
        return sqrt(x1 ** 2 + x2 ** 2)
    def kClosest(self, points: List[List[int]], k: int) -> List[List[int]]:
        if not points:
            return
        if len(points) == 1:
            return points

        hq = []
        hmap = {}
        l = 0

        for point in points:
            d = self.pointDistance(point[0], point[1])
            if l < k:
                l += 1
                heapq.heappush(hq, -d)
                if d not in hmap:
                    hmap[d] = [point]
                else:
                    hmap[d].append(point)
            elif l == k:
                temp = -hq[0]
                if d < abs(temp):
                    temp = heapq.heappop(hq)

                    if len(hmap[-temp]) > 1:
                        hmap[-temp].pop(0)
                    else:
                        del hmap[-temp]

                    heapq.heappush(hq, -d)

                    if d not in hmap:
                        hmap[d] = [point]
                    else:
                        hmap[d].append(point)

        ret = []
        for key in hmap:
            for value in hmap[key]:
                ret.append(value)

        return ret

class Solution:
