            while stk and stk[-1] > 0 and ast < 0:
                # Stack top smaller
                if stk[-1] < -ast:
                    stk.pop()
                    continue

                # Same Size
                elif stk[-1] == -ast:
                    stk.pop()
                    ast = 0
                    break

                # Stack top larger. Incoming ast explodes
                else:
                    ast = 0
                    break
            # Only executes if incoming ast survives and is not 0
            if ast:
                stk.append(ast)

