        # Binary Search for optimal starting index of k-element window.
        # Window = arr[low : low + k]
        low = 0
        high = n - k

        while low < high:
            mid = (high + low) // 2
            if arr[mid] == arr[mid + k]:
                if arr[mid] < x:low = mid + 1
                else:high = mid
            elif abs(x-arr[mid]) <= abs(x - arr[mid + k]):
                high = mid
            else:
                low = mid + 1

        return arr[low : low + k]

