        while i < n and s[i].isdigit():
            digit = int(s[i])
            ret = ret * 10 + digit

            if flag * ret <= INT_MIN:
                return INT_MIN
            if flag * ret >= INT_MAX:
                return INT_MAX

            i += 1

        return ret * flag

