class Solution:
    def rightSideView(self, root: Optional[TreeNode]) -> List[int]:
        if not root: return []

        ret = []

        dq = deque()
        dq.append(root)

        while dq:
            l = len(dq)

            for i in range(l):
                r = dq.popleft()

                if r.left:
                    dq.append(r.left)
                if r.right:
                    dq.append(r.right)
                if i == l-1:
                    ret.append(r.val)

        return ret

