        q = deque([root])

        i = 0
        while q:
            if i & 1:
                l, r = 0, len(q) - 1

                while l < r:
                    temp = q[l].val
                    q[l].val = q[r].val
                    q[r].val = temp

                    l += 1 
                    r -= 1

            for _ in range(len(q)):
                node = q.popleft()
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            i += 1
        return root

