        hmap = {}
        C = []
        c = 0
        for i in range(0, len(A)):

            if A[i] not in hmap:
                hmap[A[i]] = 1
            else:
                c = c+1
                del hmap[A[i]]

            if B[i] not in hmap:
                hmap[B[i]] = 1
