            totalcal = totalcal + calories[i] - calories[i-k]

            if totalcal > upper:
                score += 1
                #print(f"yes {score}")
            elif totalcal < lower:
                score -= 1
                #print(f"no {score}")
            else:
                #print(f"ignored {score}")
                continue

        return score

